var adapter = new PrismaPg({ connectionString });
var prisma = new PrismaClient({ adapter });

// src/user/user.service.ts
var registerUserIntoDB = async (payload) => {
  const { name, email, password, profilePhoto, role } = payload;
  const isUserExit = await prisma.user.findUnique({
    where: { email }
  });
  if (isUserExit) {
    throw new Error("User with this email already exists");
  }
  const hashedPassword = await bcrypt.hash(
    password,
    Number(config_default.bcrypt_salt_rounds)
  );
  const createUser = await prisma.user.create({
    data: {
      name,
      email,
      password: hashedPassword,
      role,
      profile: {
        create: {
          profilePhoto
        }
      }
    }
  });
  const user = await prisma.user.findUnique({
    where: {
      id: createUser.id,
      email: createUser.email || email
    },
    omit: {
      password: true
    },
    include: {
      profile: true
    }
  });
  return user;
};
var getMyProfileFromDB = async (userId) => {
  const user = await prisma.user.findUniqueOrThrow({
    where: { id: userId },
    omit: {
      password: true
    },
    include: {
      profile: true
    }
  });
  return user;
};
var getAllUsersFromDB = async () => {
  const users = await prisma.user.findMany({
    where: {
      role: {
        in: [Role.LANDLORD, Role.TENANT]
      }
    },
    omit: {
      password: true
    },
    include: {
      profile: true
    }
  });
  return users;
};
var updateUserStatusIntoDB = async (adminId, userId, status) => {
  const admin = await prisma.user.findUniqueOrThrow({
    where: {
      id: adminId
    }
  });
  if (admin.role !== Role.ADMIN) {
    throw new Error("Only admin can update user status.");
  }
  const result = await prisma.user.update({
    where: {
      id: userId
    },
    data: {
      status
    }
  });
  return result;
};
var getAllPropertiesFromDB = async () => {
  const result = await prisma.property.findMany();
  return result;
};
var getAllRentalsRequestFromDB = async () => {
  const result = await prisma.rentalRequest.findMany({
    include: {
      property: true,
      tenant: true
    },
    omit: {
      propertyId: true
    }
  });
  return result;
};
