var getAllPropertyFromDB = async (query) => {
  const andConditions = [];
  if (query.location) {
    andConditions.push({
      location: {
        contains: query.location,
        mode: "insensitive"
      }
    });
  }
  if (query.price) {
    andConditions.push({
      price: {
        lte: Number(query.price)
      }
    });
  }
  const result = await prisma.property.findMany({
    where: {
      AND: andConditions
    },
    orderBy: {
      createdAt: "asc"
    },
    include: {
      landlord: {
        omit: {
          password: true
        }
      }
    }
  });
  return result;
};
